import React, { useState, useEffect } from 'react';
import Table from '../Reusable/Table.tsx';
import SidePanel from '../Reusable/Sidepanel.tsx';
import AddService from './AddService.tsx';

const Services = () => {
    const [serviceData, setServiceData] = useState<any[]>([]);
    const [isAddPanelOpen, setisAddPanelOpen] = useState(false);
    const [isEditPanelOpen, setisEditPanelOpen] = useState(false);
    const [currentItem, setCurrentItem] = useState(null);

    //when mounting fetch all service data
    useEffect(() => {
        const fetchServiceData = async () => {
            try{
                const token = localStorage.getItem('token');
                const response = await fetch('http://localhost:3000/api/services', {
                    headers: { Authorization : `Bearer ${token}`} 
                });
                if (!response.ok) {
                    throw new Error ('Failed to fetch services data');
                }
                const data = await response.json();
                setServiceData(data);
            }catch(error){
                console.error('Error fetching services data', error);
            }
        }
        fetchServiceData();
    }, [])

    //create a new service
    const handleAdd = async (newService) => {
        const newService_ = {
            ... newService,
            price: Number(newService.price)
        }
        const token = localStorage.getItem('token');
        const response = await fetch ('http://localhost:3000/api/services', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 
                       'Authorization': `Bearer ${token}`},
            body: JSON.stringify(newService_)
        });

        if (response.ok) {
            const addedService = await response.json();
            setServiceData([...serviceData, addedService]);
        }else {
            throw new Error("Error adding service")
        }
    }

    //edit a service

    //delete a service


    //define columns
    const columns = [
        { header: 'Service Name', accessor: 'name'},
        { header: 'Description', accessor: 'description'},
        { header: 'Price', accessor: 'price'},
        { header: 'Date', accessor: 'createdAt'},
    ];

    return(
        <div className='table-container'>
            <h2>Services</h2>
            <button onClick={() => setisAddPanelOpen(true)}>Add Service</button>
            <Table columns={columns} data={serviceData} onDelete={null} onEdit={(item)=>{{setCurrentItem(item)};setisEditPanelOpen(true)}}/>
            <SidePanel isOpen={isAddPanelOpen} onClose={() => setisAddPanelOpen(false)}>
                <AddService onAdd = {handleAdd} onClose={() => setisAddPanelOpen(false)}/>
            </SidePanel>
            {/* {currentItem && <SidePanel isOpen={isEditPanelOpen} onClose={() => setisEditPanelOpen(false)}>
                <EditInventory item={currentItem} onUpdate = {handleUpdate} onClose={() => setisEditPanelOpen(false)}/>
            </SidePanel>} */}

        </div>
    )

}

export default Services;
